import{_ as e,o as s,c as a,ag as r}from"./chunks/framework.DXGyWiRo.js";const m=JSON.parse('{"title":"OS Management Functions","description":"","frontmatter":{},"headers":[],"relativePath":"theory/systems/os-management.md","filePath":"theory/systems/os-management.md"}'),o={name:"theory/systems/os-management.md"};function n(i,t,d,l,c,h){return s(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="os-management-functions" tabindex="-1">OS Management Functions <a class="header-anchor" href="#os-management-functions" aria-label="Permalink to &quot;OS Management Functions&quot;">​</a></h1><p>The operating system doesn&#39;t just provide a desktop — it is constantly working behind the scenes managing files, memory, processes, and devices. Understanding what an OS manages is core Paper 2 content.</p><div class="note custom-block github-alert"><p class="custom-block-title">Grade 10+</p><p>OS management functions are introduced in Grade 10. File management, backup, and compression are key Gr10 topics. Virtualisation links to Grade 12.</p></div><hr><h2 id="os-core-functions-—-overview" tabindex="-1">OS Core Functions — Overview <a class="header-anchor" href="#os-core-functions-—-overview" aria-label="Permalink to &quot;OS Core Functions — Overview&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Function</th><th>What the OS does</th></tr></thead><tbody><tr><td><strong>File management</strong></td><td>Organises files in folders; handles read/write/delete operations</td></tr><tr><td><strong>Process management</strong></td><td>Controls which programs run and how much CPU time they get</td></tr><tr><td><strong>Memory management</strong></td><td>Allocates RAM to programs; manages virtual memory</td></tr><tr><td><strong>Device management</strong></td><td>Communicates with hardware via drivers</td></tr><tr><td><strong>Security</strong></td><td>User accounts, passwords, access permissions, firewalls</td></tr><tr><td><strong>User interface</strong></td><td>Provides GUI or CLI for user interaction</td></tr></tbody></table><hr><h2 id="file-management" tabindex="-1">File Management <a class="header-anchor" href="#file-management" aria-label="Permalink to &quot;File Management&quot;">​</a></h2><p>The OS organises all data on storage devices using a <strong>hierarchical folder structure</strong> (directory tree).</p><h3 id="file-system-concepts" tabindex="-1">File System Concepts <a class="header-anchor" href="#file-system-concepts" aria-label="Permalink to &quot;File System Concepts&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Concept</th><th>Explanation</th></tr></thead><tbody><tr><td><strong>File</strong></td><td>A named collection of data stored on a storage device</td></tr><tr><td><strong>Folder/Directory</strong></td><td>A container that organises files</td></tr><tr><td><strong>Path</strong></td><td>Full address of a file: <code>C:\\Users\\Ayden\\Documents\\notes.txt</code></td></tr><tr><td><strong>Extension</strong></td><td>Letters after the dot indicating file type: <code>.docx</code>, <code>.py</code>, <code>.txt</code></td></tr><tr><td><strong>Root directory</strong></td><td>Top-level folder — <code>C:\\</code> on Windows, <code>/</code> on Linux</td></tr><tr><td><strong>Absolute path</strong></td><td>Full path from root: <code>C:\\Users\\Ayden\\file.txt</code></td></tr><tr><td><strong>Relative path</strong></td><td>Path relative to current location: <code>..\\file.txt</code></td></tr></tbody></table><h3 id="common-file-extensions" tabindex="-1">Common File Extensions <a class="header-anchor" href="#common-file-extensions" aria-label="Permalink to &quot;Common File Extensions&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Extension</th><th>Type</th></tr></thead><tbody><tr><td><code>.docx</code></td><td>Word document</td></tr><tr><td><code>.xlsx</code></td><td>Excel spreadsheet</td></tr><tr><td><code>.pdf</code></td><td>Portable Document Format</td></tr><tr><td><code>.jpg / .jpeg</code></td><td>JPEG image</td></tr><tr><td><code>.png</code></td><td>PNG image (lossless)</td></tr><tr><td><code>.mp3</code></td><td>Audio (compressed)</td></tr><tr><td><code>.mp4</code></td><td>Video (compressed)</td></tr><tr><td><code>.exe</code></td><td>Windows executable</td></tr><tr><td><code>.py</code></td><td>Python source code</td></tr><tr><td><code>.txt</code></td><td>Plain text</td></tr><tr><td><code>.zip</code></td><td>Compressed archive</td></tr></tbody></table><h3 id="file-system-types" tabindex="-1">File System Types <a class="header-anchor" href="#file-system-types" aria-label="Permalink to &quot;File System Types&quot;">​</a></h3><table tabindex="0"><thead><tr><th>File System</th><th>OS</th><th>Features</th></tr></thead><tbody><tr><td><strong>NTFS</strong></td><td>Windows</td><td>Permissions, encryption, large files, journaling</td></tr><tr><td><strong>FAT32</strong></td><td>Universal</td><td>Wide compatibility, max 4 GB file size</td></tr><tr><td><strong>exFAT</strong></td><td>USB drives</td><td>Large files, cross-platform</td></tr><tr><td><strong>ext4</strong></td><td>Linux</td><td>Journaling, large files, fast</td></tr><tr><td><strong>APFS</strong></td><td>macOS</td><td>Encryption, snapshots, optimised for SSDs</td></tr></tbody></table><hr><h2 id="process-management" tabindex="-1">Process Management <a class="header-anchor" href="#process-management" aria-label="Permalink to &quot;Process Management&quot;">​</a></h2><p>A <strong>process</strong> is a program that is currently being executed by the CPU.</p><p>The OS manages multiple processes via <strong>multitasking</strong>:</p><ul><li><strong>Time-slicing</strong>: each process gets a tiny slice of CPU time, switching rapidly</li><li><strong>Context switching</strong>: saving one process&#39;s state while loading another</li><li><strong>Process scheduler</strong>: decides which process runs next (priority-based)</li></ul><p><strong>Task Manager</strong> (Windows) shows all running processes and their CPU/RAM usage. You can end unresponsive processes here.</p><hr><h2 id="memory-management" tabindex="-1">Memory Management <a class="header-anchor" href="#memory-management" aria-label="Permalink to &quot;Memory Management&quot;">​</a></h2><p>The OS allocates RAM to programs as needed and reclaims it when programs close.</p><h3 id="virtual-memory" tabindex="-1">Virtual Memory <a class="header-anchor" href="#virtual-memory" aria-label="Permalink to &quot;Virtual Memory&quot;">​</a></h3><p>When physical RAM is full, the OS uses a portion of the hard drive as <strong>virtual memory</strong> (swap space / page file):</p><ul><li>Data from RAM is temporarily moved to a swap file on disk</li><li>The process can continue running even with insufficient RAM</li><li><strong>Significantly slower</strong> than physical RAM (disk access vs RAM access)</li><li>Heavy virtual memory use causes noticeable slowdowns</li></ul><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Fast RAM (8 GB) ←→ Slow Disk (swap file) — managed by OS</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><hr><h2 id="device-management" tabindex="-1">Device Management <a class="header-anchor" href="#device-management" aria-label="Permalink to &quot;Device Management&quot;">​</a></h2><p>Every hardware device needs a <strong>driver</strong> — a small program letting the OS communicate with that specific device.</p><p><strong>Plug and Play process:</strong></p><ol><li>Device is connected</li><li>OS detects new hardware</li><li>OS finds and loads the appropriate driver</li><li>Device is ready to use</li></ol><p><strong>Driver problems:</strong></p><ul><li>Outdated → device malfunction</li><li>Missing → device not recognised</li><li>Wrong → system instability or BSOD (Blue Screen of Death)</li></ul><hr><h2 id="file-compression" tabindex="-1">File Compression <a class="header-anchor" href="#file-compression" aria-label="Permalink to &quot;File Compression&quot;">​</a></h2><p><strong>Compression</strong> reduces file size by encoding data more efficiently.</p><table tabindex="0"><thead><tr><th>Type</th><th>Method</th><th>Quality</th><th>Examples</th></tr></thead><tbody><tr><td><strong>Lossless</strong></td><td>Removes redundant patterns; fully reversible</td><td>No quality loss</td><td>ZIP, 7-ZIP, PNG, FLAC</td></tr><tr><td><strong>Lossy</strong></td><td>Permanently removes detail</td><td>Reduced quality</td><td>JPEG, MP3, MP4</td></tr></tbody></table><p><strong>Why compress?</strong></p><ul><li>Save storage space</li><li>Faster transfer (smaller file = less bandwidth/time)</li><li>Bundle multiple files into one archive</li></ul><hr><h2 id="backup" tabindex="-1">Backup <a class="header-anchor" href="#backup" aria-label="Permalink to &quot;Backup&quot;">​</a></h2><p><strong>Backup</strong> is the process of copying data to a separate location so it can be restored if the original is lost or corrupted.</p><p><strong>Threats that make backup essential:</strong></p><ul><li>Hardware failure (HDD crash)</li><li>Ransomware attack</li><li>Accidental deletion</li><li>Physical theft or damage</li><li>Fire or flood</li></ul><h3 id="backup-types" tabindex="-1">Backup Types <a class="header-anchor" href="#backup-types" aria-label="Permalink to &quot;Backup Types&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Type</th><th>What it backs up</th><th>Speed</th><th>Storage</th></tr></thead><tbody><tr><td><strong>Full backup</strong></td><td>All selected data every time</td><td>Slowest</td><td>Most</td></tr><tr><td><strong>Incremental</strong></td><td>Only changes since last backup</td><td>Fastest</td><td>Least</td></tr><tr><td><strong>Differential</strong></td><td>Changes since last FULL backup</td><td>Medium</td><td>Medium</td></tr></tbody></table><h3 id="the-3-2-1-rule" tabindex="-1">The 3-2-1 Rule <a class="header-anchor" href="#the-3-2-1-rule" aria-label="Permalink to &quot;The 3-2-1 Rule&quot;">​</a></h3><ul><li><strong>3</strong> copies of data</li><li><strong>2</strong> different storage media types</li><li><strong>1</strong> copy offsite (or cloud)</li></ul><h3 id="backup-media-options" tabindex="-1">Backup Media Options <a class="header-anchor" href="#backup-media-options" aria-label="Permalink to &quot;Backup Media Options&quot;">​</a></h3><ul><li>External HDD/SSD</li><li>USB flash drive</li><li>Cloud backup (Google Drive, OneDrive, iCloud)</li><li>Network-attached storage (NAS)</li><li>Tape (large organisations, archival)</li></ul><hr><h2 id="disk-defragmentation" tabindex="-1">Disk Defragmentation <a class="header-anchor" href="#disk-defragmentation" aria-label="Permalink to &quot;Disk Defragmentation&quot;">​</a></h2><p>Over time, HDD files get split into fragments scattered across the disk. <strong>Defragmentation</strong> rearranges fragments so files are stored contiguously, improving read speed.</p><div class="warning custom-block github-alert"><p class="custom-block-title">SSDs Do NOT Need Defragmentation</p><p>Defragmenting an SSD causes unnecessary writes that shorten its lifespan, with no speed benefit. Modern Windows skips defrag on SSDs automatically.</p></div><hr><h2 id="user-accounts-and-permissions" tabindex="-1">User Accounts and Permissions <a class="header-anchor" href="#user-accounts-and-permissions" aria-label="Permalink to &quot;User Accounts and Permissions&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Account Type</th><th>Windows</th><th>Capabilities</th></tr></thead><tbody><tr><td><strong>Administrator</strong></td><td>Full</td><td>Install software, change settings, manage users</td></tr><tr><td><strong>Standard user</strong></td><td>Limited</td><td>Run programs, manage own files; cannot install system software</td></tr><tr><td><strong>Guest</strong></td><td>Minimal</td><td>Temporary access, no changes</td></tr></tbody></table><h3 id="file-permissions" tabindex="-1">File Permissions <a class="header-anchor" href="#file-permissions" aria-label="Permalink to &quot;File Permissions&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Permission</th><th>Meaning</th></tr></thead><tbody><tr><td><strong>Read</strong></td><td>View file content</td></tr><tr><td><strong>Write</strong></td><td>Modify file content</td></tr><tr><td><strong>Execute</strong></td><td>Run a program</td></tr><tr><td><strong>Full control</strong></td><td>All permissions + change others&#39; permissions</td></tr></tbody></table><hr><h2 id="key-terms" tabindex="-1">Key Terms <a class="header-anchor" href="#key-terms" aria-label="Permalink to &quot;Key Terms&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Term</th><th>Definition</th></tr></thead><tbody><tr><td><strong>Process</strong></td><td>Program currently executing in memory</td></tr><tr><td><strong>Multitasking</strong></td><td>OS runs multiple processes apparently simultaneously</td></tr><tr><td><strong>Virtual memory</strong></td><td>Using disk space as extra RAM when physical RAM is full</td></tr><tr><td><strong>Driver</strong></td><td>Software allowing OS to communicate with hardware</td></tr><tr><td><strong>Defragmentation</strong></td><td>Rearranging HDD file fragments for faster access</td></tr><tr><td><strong>Compression</strong></td><td>Reducing file size by encoding more efficiently</td></tr><tr><td><strong>Lossless</strong></td><td>Compression with no quality loss — file fully recoverable</td></tr><tr><td><strong>Lossy</strong></td><td>Compression that permanently removes detail</td></tr><tr><td><strong>Backup</strong></td><td>Copy of data stored separately for recovery</td></tr><tr><td><strong>Incremental backup</strong></td><td>Only backs up changes since last backup</td></tr><tr><td><strong>Full backup</strong></td><td>Backs up all selected data completely</td></tr><tr><td><strong>Permissions</strong></td><td>Access rights granted to users for files/folders</td></tr></tbody></table><hr><h2 id="exam-focus" tabindex="-1">Exam Focus <a class="header-anchor" href="#exam-focus" aria-label="Permalink to &quot;Exam Focus&quot;">​</a></h2><div class="important custom-block github-alert"><p class="custom-block-title">High-Frequency Questions</p><p></p><ol><li><p><strong>&quot;Give TWO functions of an operating system&quot;</strong> — name + explain each: &quot;File management — organises files in folders and handles read/write/delete operations&quot;</p></li><li><p><strong>&quot;What is virtual memory?&quot;</strong> — uses disk space as extra RAM when physical RAM is full; slower than actual RAM</p></li><li><p><strong>&quot;Explain the difference between full and incremental backup&quot;</strong> — full = all data copied every time; incremental = only changes since last backup (faster, uses less storage)</p></li><li><p><strong>&quot;Explain lossless vs lossy compression. Give an example of each.&quot;</strong> — lossless: no quality loss, file fully recoverable (ZIP, PNG); lossy: some quality removed permanently (JPEG, MP3)</p></li><li><p><strong>&quot;Why should you NOT defragment an SSD?&quot;</strong> — no moving parts; unnecessary writes shorten lifespan; no speed benefit</p></li></ol></div>',67)])])}const p=e(o,[["render",n]]);export{m as __pageData,p as default};
